// Map sheet rows -> Ramsisa locations[] payload (one rep's clients).
// Field names match the Ramsisa API exactly (https://schedule.ramsisa.com/docs/api-reference/):
//   id, name, tier (A|B|C), territory, latitude, longitude
// Optional: available_from, available_to, available_days.
//
// The sheet may use canonical names (id/latitude/longitude) or short aliases
// (ID/lat/lng); both are accepted here. available_days accepts comma, semicolon,
// whitespace, or pipe as separators.
//
// `territory` here is the rep's own sub-area (e.g. north vs. south of their
// patch) — Ramsisa uses it to keep day-routes geographically tight. It is NOT
// a different rep.

const DAY_ALIASES = {
  sat: 'saturday', sun: 'sunday', mon: 'monday', tue: 'tuesday', wed: 'wednesday', thu: 'thursday', fri: 'friday',
};

const locations = $input.all().map((item) => {
  const r = item.json;
  const loc = {
    id: String(r.id ?? r.ID ?? '').trim(),
    name: String(r.name ?? '').trim(),
    tier: String(r.tier ?? '').trim().toUpperCase(),
    territory: String(r.territory ?? '').trim(),
    latitude: Number(r.latitude ?? r.lat),
    longitude: Number(r.longitude ?? r.lng),
  };
  if (r.available_from) loc.available_from = String(r.available_from);
  if (r.available_to) loc.available_to = String(r.available_to);
  if (r.available_days) {
    loc.available_days = String(r.available_days)
      .split(/[,;|\s]+/)
      .filter(Boolean)
      .map((s) => s.toLowerCase())
      .map((s) => DAY_ALIASES[s] || s);
  }
  return loc;
});

const missing = locations.filter((l) => !l.id || !l.tier || Number.isNaN(l.latitude) || Number.isNaN(l.longitude));
if (missing.length) {
  throw new Error(`${missing.length} row(s) missing id/tier/latitude/longitude`);
}

return [{ json: { locations } }];
